html:
{%- if letter_head and not no_letterhead -%}
    {{ letter_head }}
{%- endif -%}

<style>
    .tech-block {
        direction: rtl;
        font-family: 'Segoe UI', Tahoma, Arial, sans-serif;
        line-height: 1.8;
        color: #000;
        position: relative;
    }

    /* تنسيق الإشاري والتاريخ ليكون في أعلى اليسار فوق الخط */
    .reference-section {
        text-align: left;
        font-size: 13px;
        margin-bottom: 5px; /* مسافة بسيطة قبل الخط العلوي للعنوان */
        padding-left: 5px;
    }

    .document-title {
        text-align: center;
        font-size: 24px;
        font-weight: bold;
        color: #000;
        border-top: 2px solid #000;
        border-bottom: 2px solid #000;
        padding: 15px 0;
        margin-bottom: 30px;
    }

    .client-details {
        border: 1px solid #e0e0e0;
        border-right: 4px solid #000;
        padding: 15px 20px;
        margin-bottom: 35px;
        background: #f9f9f9;
    }

    .client-details p { margin: 8px 0; font-size: 15px; }
    .client-details strong { display: inline-block; min-width: 160px; }

    .quotation-section { margin-bottom: 40px; }

    .tech-content-body {
        position: relative;
        overflow-x: hidden;
        padding-left: 20px;
    }

    /* تنسيق العناوين السوداء */
    .tech-content-body h1, .tech-content-body h2, .tech-content-body h3,
    .tech-content-body h4, .tech-content-body h5, .tech-content-body h6 {
        position: relative !important;
        display: inline-block !important;
        background: #000 !important;
        color: #fff !important;
        padding: 8px 18px !important;
        margin-top: 25px !important;
        margin-bottom: 15px !important;
        font-size: 18px !important;
        border-radius: 2px !important;
        z-index: 5 !important;
    }

    /* الخطوط المائلة الجانبية */
    .tech-content-body h1::before, .tech-content-body h2::before, .tech-content-body h3::before,
    .tech-content-body h4::before, .tech-content-body h5::before, .tech-content-body h6::before {
        content: "";
        position: absolute !important;
        top: 0;
        right: 100%;
        width: 350px; 
        height: 100%;
        background-image: repeating-linear-gradient(45deg, #000, #000 2px, transparent 2px, transparent 6px) !important;
        z-index: -1;
    }

    .tech-content-body p { margin: 10px 0; text-align: justify; }
    .tech-content-body ul { padding-right: 25px; list-style-type: square; }
</style>

<div class="tech-block">

    <!-- قسم الإشاري والتاريخ يظهر هنا أولاً (فوق الخط) -->
    <div class="reference-section">
        <p style="margin: 0;"><strong>الإشاري:</strong> {{ doc.name }}</p>
        <p style="margin: 0;"><strong>التاريخ:</strong> {{ doc.get_formatted("transaction_date") }}</p>
    </div>

    <div class="document-title">
        العرض الفني والمالي
    </div>

    <div class="client-details">
        <p><strong>اسم العميل:</strong> {{ doc.customer_name or "" }}</p>
        <p><strong>عنوان المشروع:</strong> {{ doc.project_name or "" }}</p>
    </div>

    {% if doc.items and doc.items|length > 0 %}
        {% for row in doc.items %}
            <div class="quotation-section">
                <div class="tech-content-body">
                    {% set content = row.technical_content or doc.technical_content or "" %}

                    {# استبدال المتغيرات #}
                    {% set content = content.replace("{{price_from}}", (row.price_from or 0)|string) %}
                    {% set content = content.replace("{{price_to}}", (row.price_to or 0)|string) %}
                    {% set content = content.replace("{{total_from}}", (doc.total_from or 0)|string) %}
                    {% set content = content.replace("{{total_to}}", (doc.total_to or 0)|string) %}

                    {{ content | safe }}
                </div>
            </div>
        {% endfor %}
    {% else %}
        <div class="tech-content-body">
            {% set content = doc.technical_content or "" %}
            {{ content | safe }}
        </div>
    {% endif %}

</div>

{%- if footer and not no_letterhead -%}
    {{ footer }}
{%- endif -%}
